dslRule:
@id: jdt.internal.importrewrite.addimport.annotationtype.other
@severity: info
addImport($annotation.getAnnotationType(), $ast, $context) :: sourceVersionGE(8) && instanceof($annotation, "org.eclipse.jdt.core.dom.IAnnotationBinding")
=> addImport($annotation.getAnnotationType(), $ast, $context, org.eclipse.jdt.core.dom.rewrite.ImportRewrite.TypeLocation.OTHER)
;;

@id: jdt.internal.importrewrite.buildtype.recursive.other
@severity: info
buildType($binding.getDeclaringClass(), $bindingPoint, $ast, $context, $qualifier) :: sourceVersionGE(8) && instanceof($binding, "org.eclipse.jdt.core.dom.ITypeBinding")
=> buildType($binding.getDeclaringClass(), $bindingPoint, $ast, $context, $qualifier, org.eclipse.jdt.core.dom.rewrite.ImportRewrite.TypeLocation.OTHER)
;;

@id: jdt.internal.importrewrite.addimport.typeliteral.other
@severity: info
addImport($value, $ast, $context) :: sourceVersionGE(8) && instanceof($value, "org.eclipse.jdt.core.dom.ITypeBinding")
=> addImport($value, $ast, $context, org.eclipse.jdt.core.dom.rewrite.ImportRewrite.TypeLocation.OTHER)
;;

@id: jdt.internal.importrewrite.addimport.variabletype.other
@severity: info
addImport($variable.getType(), $ast, $context) :: sourceVersionGE(8) && instanceof($variable, "org.eclipse.jdt.core.dom.IVariableBinding")
=> addImport($variable.getType(), $ast, $context, org.eclipse.jdt.core.dom.rewrite.ImportRewrite.TypeLocation.OTHER)
;;

@id: jdt.internal.importrewrite.addimport.typebound
@severity: info
addImport($bound, $ast, $context) :: sourceVersionGE(8) && instanceof($bound, "org.eclipse.jdt.core.dom.ITypeBinding")
=> addImport($bound, $ast, $context, org.eclipse.jdt.core.dom.rewrite.ImportRewrite.TypeLocation.TYPE_BOUND)
;;

@id: jdt.internal.importrewrite.addimport.arraycontents
@severity: info
addImport($normalizedBinding.getElementType(), $ast, $context) :: sourceVersionGE(8) && instanceof($normalizedBinding, "org.eclipse.jdt.core.dom.ITypeBinding")
=> addImport($normalizedBinding.getElementType(), $ast, $context, org.eclipse.jdt.core.dom.rewrite.ImportRewrite.TypeLocation.ARRAY_CONTENTS)
;;

@id: jdt.internal.importrewrite.addimport.typeargument
@severity: info
addImport($curr, $ast, $context) :: sourceVersionGE(8) && instanceof($curr, "org.eclipse.jdt.core.dom.ITypeBinding")
=> addImport($curr, $ast, $context, org.eclipse.jdt.core.dom.rewrite.ImportRewrite.TypeLocation.TYPE_ARGUMENT)
;;

/*!id: jdt.internal.importrewrite.addimport.2arg-to-4arg-delegation*/
/*!description: Updates internal delegation for 2-argument ImportRewrite.addImport to use new 4-argument overload, passing TypeLocation.UNKNOWN. This rule targets the 'return addImport(binding, ast, this.defaultContext);' line inside the 2-arg public method.*/
@severity: info
org.eclipse.jdt.core.dom.rewrite.ImportRewrite.$this.addImport($binding, $ast, this.defaultContext)
:: inClass("org.eclipse.jdt.core.dom.rewrite.ImportRewrite") && inMethod("addImport") && paramCount(2)
=> $this.addImport($binding, $ast, this.defaultContext, org.eclipse.jdt.core.dom.rewrite.ImportRewrite.TypeLocation.UNKNOWN)
;;

/*!id: jdt.internal.importrewrite.addimport.3arg-to-4arg-delegation*/
/*!description: Updates internal delegation for 3-argument ImportRewrite.addImport to use new 4-argument overload, passing TypeLocation.UNKNOWN. This rule targets the 'return addImport(binding, ast, context);' line inside the 3-arg public method.*/
@severity: info
org.eclipse.jdt.core.dom.rewrite.ImportRewrite.$this.addImport($binding, $ast, $context)
:: inClass("org.eclipse.jdt.core.dom.rewrite.ImportRewrite") && inMethod("addImport") && paramCount(3)
=> $this.addImport($binding, $ast, $context, org.eclipse.jdt.core.dom.rewrite.ImportRewrite.TypeLocation.UNKNOWN)
;;

/*!id: jdt.internal.importrewrite.addimport.callsite.addannotation*/
/*!description: Adds TypeLocation.OTHER argument to the internal addImport call within ImportRewrite.addAnnotation. This rule targets the specific addImport invocation inside the addAnnotation method.*/
@severity: info
org.eclipse.jdt.core.dom.rewrite.ImportRewrite.$this.addImport($annotation.getAnnotationType(), $ast, $context)
:: inClass("org.eclipse.jdt.core.dom.rewrite.ImportRewrite") && inMethod("addAnnotation")
=> $this.addImport($annotation.getAnnotationType(), $ast, $context, org.eclipse.jdt.core.dom.rewrite.ImportRewrite.TypeLocation.OTHER)
;;

