dslRule:
/*!id: jdt.internal.moduledeclaration.modifiers-to-annotations-method*/
/*!description: Updates internal JDT AST consumers to use ModuleDeclaration.annotations() instead of the deprecated ModuleDeclaration.modifiers().*/
/*!severity: info*/
/*!minJavaVersion: 9*/
/*!tags: jdt, internal, refactoring, java9*/
org.eclipse.jdt.core.dom.ModuleDeclaration.$node.modifiers() :: sourceVersionGE(9)
=> org.eclipse.jdt.core.dom.ModuleDeclaration.$node.annotations()
;;

/*!id: jdt.internal.moduledeclaration.modifiers-property-to-annotations-property*/
/*!description: Updates internal JDT AST consumers to use ModuleDeclaration.ANNOTATIONS_PROPERTY instead of the deprecated ModuleDeclaration.MODIFIERS_PROPERTY.*/
/*!severity: info*/
/*!minJavaVersion: 9*/
/*!tags: jdt, internal, refactoring, java9*/
org.eclipse.jdt.core.dom.ModuleDeclaration.MODIFIERS_PROPERTY :: sourceVersionGE(9)
=> org.eclipse.jdt.core.dom.ModuleDeclaration.ANNOTATIONS_PROPERTY
;;

/*!id: jdt.internal.moduledeclaration.astconverter.settype-to-setname*/
/*!description: Updates internal JDT DOM ASTConverter logic to use name-based setters for ModuleDirective nodes, replacing type-based setters.*/
/*!severity: info*/
$moduleDirective.setType(this.convertType($typeRef)) :: (instanceof($moduleDirective, "org.eclipse.jdt.core.dom.UsesDirective") || instanceof($moduleDirective, "org.eclipse.jdt.core.dom.ProvidesDirective"))
=> $moduleDirective.setName(this.convert($typeRef))
;;

/*!id: jdt.internal.moduledeclaration.astconverter.implementations-addtype-to-addname*/
/*!description: Updates internal JDT DOM ASTConverter logic for ProvidesDirective to use name-based additions for implementations, replacing type-based additions.*/
/*!severity: info*/
$providesDirective.implementations().add(this.convertType($typeRef)) :: instanceof($providesDirective, "org.eclipse.jdt.core.dom.ProvidesDirective")
=> $providesDirective.implementations().add(this.convert($typeRef))
;;

/*!id: jdt.internal.moduledeclaration.astmatcher.gettype-to-getname*/
/*!description: Updates internal JDT DOM ASTMatcher logic to use name-based getters for ModuleDirective nodes, replacing type-based getters.*/
/*!severity: info*/
$node.getType() :: (instanceof($node, "org.eclipse.jdt.core.dom.UsesDirective") || instanceof($node, "org.eclipse.jdt.core.dom.ProvidesDirective"))
=> $node.getName()
;;

/*!id: jdt.internal.moduledeclaration.naiveastflattener.gettype-to-getname*/
/*!description: Updates internal JDT DOM NaiveASTFlattener logic to use name-based getters for ModuleDirective nodes, replacing type-based getters.*/
/*!severity: info*/
$node.getType().accept($this)
=> $node.getName().accept($this)
;;

/*!id: jdt.internal.moduledeclaration.providesdirective.type-property-to-services-property*/
/*!description: Updates internal JDT DOM ProvidesDirective.TYPE_PROPERTY to ProvidesDirective.SERVICES_PROPERTY.*/
/*!severity: info*/
org.eclipse.jdt.core.dom.ProvidesDirective.TYPE_PROPERTY
=> org.eclipse.jdt.core.dom.ProvidesDirective.SERVICES_PROPERTY
;;

/*!id: jdt.internal.moduledeclaration.usesdirective.type-property-to-name-property*/
/*!description: Updates internal JDT DOM UsesDirective.TYPE_PROPERTY to UsesDirective.NAME_PROPERTY.*/
/*!severity: info*/
org.eclipse.jdt.core.dom.UsesDirective.TYPE_PROPERTY
=> org.eclipse.jdt.core.dom.UsesDirective.NAME_PROPERTY
;;

/*!id: jdt.internal.moduledeclaration.providesdirective.services-property-to-name-property*/
/*!description: Aligns internal JDT DOM ProvidesDirective.SERVICES_PROPERTY to ProvidesDirective.NAME_PROPERTY after a previous refactoring.*/
/*!severity: info*/
org.eclipse.jdt.core.dom.ProvidesDirective.SERVICES_PROPERTY
=> org.eclipse.jdt.core.dom.ProvidesDirective.NAME_PROPERTY
;;

/*!id: jdt.internal.modulebinding.compilerbinding.field.rename*/
/*!description: Replaces moduleDeclaration.moduleBinding with moduleDeclaration.binding for consistency in JDT internal compiler AST.*/
/*!severity: info*/
/*!minJavaVersion: 9*/
/*!tags: jdt, internal, refactoring*/
$moduleDeclaration.moduleBinding :: instanceof($moduleDeclaration, "org.eclipse.jdt.internal.compiler.ast.ModuleDeclaration")
=> $moduleDeclaration.binding
;;

/*!id: jdt.internal.modulebinding.isopen.field.to.method*/
/*!description: Converts direct field access to isOpen to method call binding.isOpen() for encapsulation in JDT internal ModuleBinding.*/
/*!severity: info*/
/*!minJavaVersion: 9*/
/*!tags: jdt, internal, refactoring*/
$binding.isOpen :: instanceof($binding, "org.eclipse.jdt.internal.compiler.lookup.ModuleBinding")
=> $binding.isOpen()
;;

/*!id: jdt.internal.namelookup.findmodule.add.tochararray*/
/*!description: Modifies NameLookup.findModule() call to pass module name as char array for internal JDT module system lookup.*/
/*!severity: info*/
/*!minJavaVersion: 9*/
/*!tags: jdt, internal, refactoring*/
$nameLookup.findModule($name) :: instanceof($nameLookup, "org.eclipse.jdt.internal.core.NameLookup")
=> $nameLookup.findModule($name.toCharArray())
;;

/*!id: jdt.internal.modulebinding.getallrequiredmodules.to.getrequires*/
/*!description: Renames internal JDT ModuleBinding.getAllRequiredModules() to getRequires() for API consistency with JLS9.*/
/*!severity: info*/
/*!minJavaVersion: 9*/
/*!tags: jdt, internal, refactoring*/
$binding.getAllRequiredModules() :: instanceof($binding, "org.eclipse.jdt.internal.compiler.lookup.ModuleBinding")
=> $binding.getRequires()
;;
